using System.Text.RegularExpressions;

namespace Contoso.Text;

public sealed class StringFormatter
{
    public string FormatPhoneNumber(string digits)
    {
        ArgumentNullException.ThrowIfNull(digits);
        if (digits.Length != 10)
            throw new ArgumentException("Must be exactly 10 digits.", nameof(digits));
        return $"({digits[..3]}) {digits[3..6]}-{digits[6..]}";
    }

    public string BuildGreeting(string name, string title = "Mr.")
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(name);
        return $"Dear {title} {name},";
    }

    public string GenerateSlug(string title)
    {
        ArgumentException.ThrowIfNullOrWhiteSpace(title);
        return Regex.Replace(title.Trim().ToLowerInvariant(), @"[^a-z0-9]+", "-").Trim('-');
    }

    public string FormatCurrency(decimal amount, string symbol = "$")
    {
        return $"{symbol}{amount:F2}";
    }
}

using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    [TestMethod]
    [DataRow("1234567890", "(123) 456-7890")]
    [DataRow("5551234567", "(555) 123-4567")]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber(string digits, string expected)
    {
        var result = _formatter.FormatPhoneNumber(digits);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCodeInParens()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        Assert.StartsWith("(800)", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFourDigits()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        Assert.EndsWith("1234", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_MatchesPhonePattern()
    {
        var result = _formatter.FormatPhoneNumber("8005551234");

        Assert.MatchesRegex(@"^\(\d{3}\) \d{3}-\d{4}$", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.FormatPhoneNumber(null!));

        Assert.AreEqual("digits", ex.ParamName);
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    public void FormatPhoneNumber_WrongLength_ThrowsArgumentException(string digits)
    {
        var ex = Assert.ThrowsExactly<ArgumentException>(() => _formatter.FormatPhoneNumber(digits));

        Assert.AreEqual("digits", ex.ParamName);
    }

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.StartsWith("Dear Mr.", result);
    }

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_EndsWithNameAndComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.EndsWith("Smith,", result);
    }

    [TestMethod]
    [DataRow("Smith", "Mr.", "Dear Mr. Smith,")]
    [DataRow("Johnson", "Dr.", "Dear Dr. Johnson,")]
    [DataRow("Lee", "Ms.", "Dear Ms. Lee,")]
    public void BuildGreeting_WithTitle_ReturnsExpectedFormat(string name, string title, string expected)
    {
        var result = _formatter.BuildGreeting(name, title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void BuildGreeting_NullName_ThrowsArgumentException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.BuildGreeting(null!));
    }

    [TestMethod]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_EmptyOrWhitespaceName_ThrowsArgumentException(string name)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.BuildGreeting(name));
    }

    [TestMethod]
    [DataRow("Hello World", "hello-world")]
    [DataRow("My Blog Post!", "my-blog-post")]
    [DataRow("  Spaces Around  ", "spaces-around")]
    [DataRow("ALL CAPS TITLE", "all-caps-title")]
    public void GenerateSlug_ValidTitle_ReturnsExpectedSlug(string title, string expected)
    {
        var result = _formatter.GenerateSlug(title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void GenerateSlug_ValidTitle_MatchesSlugPattern()
    {
        var result = _formatter.GenerateSlug("Some Title Here!");

        Assert.MatchesRegex(@"^[a-z0-9]+(-[a-z0-9]+)*$", result);
    }

    [TestMethod]
    public void GenerateSlug_NullTitle_ThrowsArgumentException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.GenerateSlug(null!));
    }

    [TestMethod]
    public void FormatCurrency_PositiveAmount_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(19.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(50m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(100m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    [DataRow(19.99, "$", "$19.99")]
    [DataRow(0.5, "€", "€0.50")]
    [DataRow(1000, "£", "£1000.00")]
    public void FormatCurrency_VariousInputs_ReturnsExpectedFormat(double amount, string symbol, string expected)
    {
        var result = _formatter.FormatCurrency((decimal)amount, symbol);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatCurrency_Amount_MatchesCurrencyPattern()
    {
        var result = _formatter.FormatCurrency(1234.56m, "$");

        Assert.MatchesRegex(@"^\$\d+\.\d{2}$", result);
    }
}

